import { getAllProducts } from './db';

export type Product = {
  id: number;
  name: string;
  price: number;
};

export type SyncResult = {
  syncedAt: string;
  count: number;
};

/**
 * Returns the full product catalog with Next.js data-cache tagging.
 *
 * All callers share the same cached entry via the "products" tag, so a
 * single `revalidateTag("products")` call (e.g. from a sync action)
 * busts the cache for every view that depends on catalog data.
 *
 * Falls back to a 1-hour stale-while-revalidate window as a safety net
 * in case tag-invalidation is missed during an error.
 */
export const getCachedProducts = unstable_cache(
  async (): Promise<Product[]> => {
    console.log('[catalog] Cache MISS — fetching products from DB');
    return getAllProducts();
  },
  ['products-data'],
  {
    tags: ['products'],
    revalidate: 3600,
  },
);

/**
 * Simulates a sync with an upstream ERP/PIM system.
 *
 * In production this would batch-query the upstream, upsert into the
 * application database, and then invalidate the cache.  Here we just
 * revalidate the "products" tag so subsequent requests see fresh data.
 *
 * Returns immediately so the caller never blocks on upstream latency.
 */
export async function triggerCatalogSync(): Promise<SyncResult> {
  // Simulate a non-trivial upstream sync operation.
  // In a real system this could take seconds or minutes; the important
  // thing is that the caller (the Server Action in the page) returns
  // control to the admin browser immediately.
  const { revalidateTag } = await import('next/cache');
  revalidateTag('products');

  console.log('[catalog] Sync triggered — cache tag "products" invalidated');

  return {
    syncedAt: new Date().toISOString(),
    count: (await getAllProducts()).length,
  };
}
"}

